String inputFile = "%path";
String outputDir = "/storage/emulated/0/Tasker/projects_task/projects/whats-connect-api/system/audio-send";
String baseName = inputFile.substring(inputFile.lastIndexOf("/") + 1).replaceAll("\\.[^.]*$", "");
String outputFile = outputDir + "/" + baseName + ".opus";

String quote = new String(new char[]{34});
String newline = new String(new char[]{10});

rt = Runtime.getRuntime();
rt.exec(new String[]{"/system/bin/sh", "-c", "mkdir -p " + outputDir}).waitFor();
rt.exec(new String[]{"/system/bin/sh", "-c", "rm -f " + outputDir + "/*.mp3 " + outputDir + "/*.wav " + outputDir + "/*.m4a " + outputDir + "/*.aac " + outputDir + "/*.ogg " + outputDir + "/*.flac " + outputDir + "/*.opus " + outputDir + "/*.amr"}).waitFor();

String ffmpegCmd = "/system/bin/linker64 /data/data/net.dinglisch.android.taskerm/files/WCA/ffmpeg-wca-aarch64.bin ffmpeg -y -i " + quote + inputFile + quote + " -c:a libopus -b:a 32k -ar 24000 -ac 1 -application audio -vbr off -compression_level 10 -frame_duration 60 -packet_loss 1 -threads auto " + quote + outputFile + quote + " 2>&1";

Process p = rt.exec(new String[]{"/system/bin/sh", "-c", ffmpegCmd});
