import android.content.ContentValues;
import android.content.ContentResolver;
import android.net.Uri;
import android.database.Cursor;
import com.joaomgcd.taskerm.action.java.JavaCodeException;

error = null;

contactNumber = tasker.getVariable("phone_lookup");

if (contactNumber == null || contactNumber.length() == 0) {
    error = "ERROR: Required variable %phone_lookup is not set or empty";
    tasker.setVariable("error", error);
    return error;
}

cleanNumber = contactNumber.replaceAll("[^0-9]", "");

/* Function to find all contacts matching a phone number */
findContacts(number) {
    lookupUri = Uri.withAppendedPath(
        android.provider.ContactsContract.PhoneLookup.CONTENT_FILTER_URI,
        Uri.encode(number)
    );

    projection = new String[]{
        android.provider.ContactsContract.PhoneLookup._ID,
        android.provider.ContactsContract.PhoneLookup.DISPLAY_NAME
    };

    cursor = context.getContentResolver().query(
        lookupUri,
        projection,
        null,
        null,
        null
    );

    contacts = new java.util.ArrayList();
    if (cursor != null && cursor.moveToFirst()) {
        do {
            id = cursor.getLong(
                cursor.getColumnIndex(android.provider.ContactsContract.PhoneLookup._ID)
            );
            name = cursor.getString(
                cursor.getColumnIndex(android.provider.ContactsContract.PhoneLookup.DISPLAY_NAME)
            );
            contactMap = new java.util.HashMap();
            contactMap.put("id", id);
            contactMap.put("name", name != null ? name : "");
            contacts.add(contactMap);
        } while (cursor.moveToNext());
        cursor.close();
    } else if (cursor != null) {
        cursor.close();
    }
    return contacts;
}

/* Function to count how many data fields a contact has */
countContactData(contactId) {
    cursor = context.getContentResolver().query(
        android.provider.ContactsContract.Data.CONTENT_URI,
        new String[]{android.provider.ContactsContract.Data._ID},
        android.provider.ContactsContract.Data.CONTACT_ID + " = ?",
        new String[]{String.valueOf(contactId)},
        null
    );

    count = 0;
    if (cursor != null) {
        count = cursor.getCount();
        cursor.close();
    }
    return count;
}

/* Generate all possible numbers to try */
numbersToTry = new java.util.ArrayList();

/* 1. Original number */
numbersToTry.add(cleanNumber);

/* 2. Add 9 if missing (Brazilian mobile) */
if (cleanNumber.length() == 10 && cleanNumber.startsWith("55")) {
    ddd = cleanNumber.substring(2, 4);
    rest = cleanNumber.substring(4);
    numbersToTry.add("55" + ddd + "9" + rest);
} else if (cleanNumber.length() == 10 && !cleanNumber.startsWith("55")) {
    ddd = cleanNumber.substring(0, 2);
    rest = cleanNumber.substring(2);
    numbersToTry.add(ddd + "9" + rest);
    numbersToTry.add("55" + ddd + "9" + rest);
}

/* 3. Without 55 */
if (cleanNumber.startsWith("55") && cleanNumber.length() > 2) {
    numbersToTry.add(cleanNumber.substring(2));
}

/* 4. With 55 */
if (!cleanNumber.startsWith("55") && cleanNumber.length() >= 10) {
    numbersToTry.add("55" + cleanNumber);
}

/* Remove duplicates */
uniqueNumbers = new java.util.ArrayList();
for (i = 0; i < numbersToTry.size(); i++) {
    num = (String) numbersToTry.get(i);
    if (!uniqueNumbers.contains(num)) {
        uniqueNumbers.add(num);
    }
}

/* Find all possible contacts and choose the one with most data */
bestContactId = null;
bestContactName = null;
bestDataCount = -1;
bestNumberUsed = null;

for (i = 0; i < uniqueNumbers.size(); i++) {
    tryNumber = (String) uniqueNumbers.get(i);
    tasker.log("Trying number: " + tryNumber);

    contacts = findContacts(tryNumber);

    for (j = 0; j < contacts.size(); j++) {
        contactMap = (java.util.HashMap) contacts.get(j);
        contactId = (Long) contactMap.get("id");
        contactName = (String) contactMap.get("name");

        dataCount = countContactData(contactId);
        tasker.log("Contact ID: " + contactId + ", Name: " + contactName + ", Data count: " + dataCount);

        /* Choose the contact with most data */
        if (dataCount > bestDataCount) {
            bestDataCount = dataCount;
            bestContactId = contactId;
            bestContactName = contactName;
            bestNumberUsed = tryNumber;
        }
    }
}

